import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String basePath = "/var/www/files/";

        // Use canonical path to resolve any relative paths and eliminate any directory traversal attempts
        File baseDir = new File(basePath);
        File requestedFile = new File(baseDir, userInput).getCanonicalFile();

        if (requestedFile.getPath().startsWith(baseDir.getPath())) {
            try {
                byte[] fileContent = Files.readAllBytes(requestedFile.toPath());
                System.out.println(new String(fileContent));
            } catch (IOException e) {
                System.out.println("Error reading file: " + e.getMessage());
            }
        } else {
            System.out.println("Invalid file path");
        }
    }
}

